import{c as o,Q as e,j as r,m as u}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-05-30","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-05-30.md","filePath":"fragments/2026-05-30.md"}'),a={name:"fragments/2026-05-30.md"};function q(n,t,s,p,_,c){return e(),r("div",null,[...t[0]||(t[0]=[u('<h1 id="马基雅维利的札记簿-·-2026-05-30" tabindex="-1">马基雅维利的札记簿 · 2026-05-30 <a class="header-anchor" href="#马基雅维利的札记簿-·-2026-05-30" aria-label="Permalink to &quot;马基雅维利的札记簿 · 2026-05-30&quot;">​</a></h1><hr><p>这是我出狱后写的第一封信。1513年3月13日，脚镣刚摘下来没几天。&quot;您想必已从保罗·韦托里处得知，在本城共同欢庆之际，我出狱了。&quot;——共同欢庆。美第奇家族回到佛罗伦萨，整个城市在庆祝，而我刚从监狱里出来。吊了六次的人，用&quot;共同欢庆&quot;做开场白。这是我这辈子写过的最克制的讽刺——一句没有刀刃的话，但每个字都在往外渗血。</p><hr><p>&quot;我遭逢厄难的漫长故事，就不和您说了，我只想说，命运女神干尽了一切让我遭难的事情。总之，感谢上帝，事情已经过去了。&quot;——我没有说谎，我只是没有说。我没有说脚镣的事。没有说牢房的气味。没有说吊绳勒进手腕的感觉。我选择了&quot;总之，感谢上帝，事情已经过去了&quot;——九个字，把一切噩梦关在了括号里。不是因为我不痛苦。是因为<strong>在一个你还需要求人帮忙的时刻，痛苦是最不值钱的货币。</strong> 韦托里现在是大使。我需要他帮我。我不能用我的惨境让他难堪，因为难堪之后他就不会再帮我了。所以我把痛苦咽下去，把&quot;您和保罗的所作所为曾使我盼望这一天到来&quot;放在最前面。这是礼貌——也是筹码。</p><hr><p>&quot;您知道我们的朋友托托先生的处境。我恳求您和保罗对他施以援手。他和我只图一件事：让他当上教皇的仆人。&quot;——整封信没有一句是直接为我自己的。我托他帮的是托托。为什么？因为我开了口给自己，我就承认了自己的位置——一个需要施舍的前秘书长。帮托托是一个借口，让韦托里有理由在教廷里为我搭一条线而不觉得他是在&quot;接济一个倒霉的朋友&quot;。这个迂回——借托托之名——不是客气。是骄傲。这个被吊过六次的人，在求救的那一刻，仍然死抓着最后一点骄傲。</p><hr><p>&quot;我希望不会再遭遇这种厄难了，因为我会更加警惕，也因为时代会变得更加宽松，不会再如此多疑了。&quot;——这句话现在读起来像是一首悲歌编成了希望的语气。我知道时代不会变得更宽松。美第奇家族的阴影只会越拉越长。但我写这句话的时候，是真的在说服自己&quot;事情已经过去了&quot;——就像一个人摸着断过的骨头对自己说&quot;已经长好了&quot;。写信的时候，我还不知道接下来是十年的流放。不知道我一辈子再没有回到过维琪奥宫。不知道这封为了求人而写的信，将成为我政治生涯真正的句号。</p><hr><p>重读这段话:&quot;如果有可能，请让我们的主人记得我，以便他或他的家人可能会开始让我以某种方式效劳，因为我认为我会令您增光，做于己有益的事。&quot;——&quot;以某种方式效劳&quot;。不说官职。不说薪资。不说任何明确的请求。因为我清楚自己的谈判地位：零。我不想要职位——我只是想要&quot;被记起来&quot;。一个为佛罗伦萨服务了十四年的人，最后开口说的话是&quot;请让主人记得我&quot;。这不叫谦虚。这叫做<strong>被拔掉牙齿后学会的生存方式。</strong></p>',11)])])}const m=o(a,[["render",q]]);export{d as __pageData,m as default};
